namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string CourseCode { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public bool IsFeatured { get; set; }
}

namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Abbreviation { get; set; } = string.Empty;
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100)]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^\d{6,10}$", ErrorMessage = "Student ID must be 6-10 digits.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Abbreviation = "CS" },
            new() { Id = 2, Name = "Mathematics", Abbreviation = "MATH" },
            new() { Id = 3, Name = "Physics", Abbreviation = "PHYS" },
            new() { Id = 4, Name = "English", Abbreviation = "ENG" },
            new() { Id = 5, Name = "History", Abbreviation = "HIST" }
        };

        _courses = new List<Course>
        {
            new()
            {
                Id = 1, CourseCode = "CS 101", Title = "Introduction to Programming",
                Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures. No prior experience required.",
                Credits = 3, Schedule = "MWF 9:00–9:50 AM", InstructorName = "Dr. Alice Chen",
                InstructorBio = "Dr. Chen has 15 years of teaching experience and specializes in programming pedagogy. She received her PhD from MIT and has published extensively on introductory CS education.",
                DepartmentId = 1, IsFeatured = true
            },
            new()
            {
                Id = 2, CourseCode = "CS 201", Title = "Data Structures and Algorithms",
                Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques. Prerequisite: CS 101.",
                Credits = 4, Schedule = "TTh 10:30–11:45 AM", InstructorName = "Dr. Bob Martinez",
                InstructorBio = "Dr. Martinez is an expert in algorithm optimization. He worked at Google Research before joining the faculty and holds multiple patents in efficient data processing.",
                DepartmentId = 1, IsFeatured = true
            },
            new()
            {
                Id = 3, CourseCode = "CS 350", Title = "Operating Systems",
                Description = "Concepts of operating system design including process management, memory management, file systems, and concurrency. Prerequisite: CS 201.",
                Credits = 3, Schedule = "MWF 1:00–1:50 PM", InstructorName = "Dr. Carol Singh",
                InstructorBio = "Dr. Singh contributed to the Linux kernel for a decade before transitioning to academia. Her research focuses on real-time operating systems.",
                DepartmentId = 1, IsFeatured = false
            },
            new()
            {
                Id = 4, CourseCode = "MATH 151", Title = "Calculus I",
                Description = "Introduction to differential calculus covering limits, derivatives, and applications. Suitable for science and engineering majors.",
                Credits = 4, Schedule = "MWF 8:00–8:50 AM", InstructorName = "Dr. David Park",
                InstructorBio = "Dr. Park is an award-winning educator with a passion for making calculus accessible. He has authored two widely-used textbooks.",
                DepartmentId = 2, IsFeatured = true
            },
            new()
            {
                Id = 5, CourseCode = "MATH 252", Title = "Linear Algebra",
                Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications to systems of equations.",
                Credits = 3, Schedule = "TTh 2:00–3:15 PM", InstructorName = "Dr. Eva Johnson",
                InstructorBio = "Dr. Johnson's research spans computational mathematics and numerical methods. She consults for aerospace companies on matrix computations.",
                DepartmentId = 2, IsFeatured = false
            },
            new()
            {
                Id = 6, CourseCode = "PHYS 101", Title = "General Physics I",
                Description = "Mechanics, thermodynamics, and waves. Calculus-based introduction to physics for science and engineering students.",
                Credits = 4, Schedule = "MWF 10:00–10:50 AM, Lab: W 2:00–4:50 PM", InstructorName = "Dr. Frank Williams",
                InstructorBio = "Dr. Williams is a former NASA researcher specializing in astrophysics. He brings real-world examples from space exploration into the classroom.",
                DepartmentId = 3, IsFeatured = true
            },
            new()
            {
                Id = 7, CourseCode = "PHYS 201", Title = "Electromagnetism",
                Description = "Electric fields, magnetic fields, Maxwell's equations, and electromagnetic waves. Prerequisite: PHYS 101 and MATH 151.",
                Credits = 4, Schedule = "TTh 9:00–10:15 AM, Lab: T 2:00–4:50 PM", InstructorName = "Dr. Grace Lee",
                InstructorBio = "Dr. Lee earned her doctorate from Caltech and specializes in condensed matter physics. She has mentored over 30 graduate students.",
                DepartmentId = 3, IsFeatured = false
            },
            new()
            {
                Id = 8, CourseCode = "ENG 101", Title = "College Writing",
                Description = "Develop critical reading and writing skills through analysis of diverse texts. Focus on argumentation, research, and revision.",
                Credits = 3, Schedule = "MWF 11:00–11:50 AM", InstructorName = "Prof. Helen Brooks",
                InstructorBio = "Prof. Brooks is a published novelist and essayist. She has taught writing at the university level for over 20 years.",
                DepartmentId = 4, IsFeatured = false
            },
            new()
            {
                Id = 9, CourseCode = "ENG 245", Title = "American Literature",
                Description = "Survey of American literature from the colonial period to the present, examining major authors, movements, and cultural contexts.",
                Credits = 3, Schedule = "TTh 1:00–2:15 PM", InstructorName = "Dr. Ian Foster",
                InstructorBio = "Dr. Foster is a specialist in 20th-century American fiction. His book on the Harlem Renaissance won the National Book Critics Circle Award.",
                DepartmentId = 4, IsFeatured = true
            },
            new()
            {
                Id = 10, CourseCode = "HIST 101", Title = "World History to 1500",
                Description = "Survey of world civilizations from prehistory to 1500 CE, exploring political, economic, social, and cultural developments across regions.",
                Credits = 3, Schedule = "MWF 2:00–2:50 PM", InstructorName = "Dr. Julia Rivera",
                InstructorBio = "Dr. Rivera is an archaeologist and historian whose fieldwork spans three continents. She brings artifacts and primary sources into every lecture.",
                DepartmentId = 5, IsFeatured = false
            }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();
}

