@page "/courses"
@inject CatalogService CatalogService
@inject NavigationManager Navigation
@rendermode InteractiveServer

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search courses, codes, or instructors..."
               @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="selectedDepartmentId">
            <option value="0">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
</div>

@if (courses.Any())
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th>Schedule</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.CourseCode</td>
                    <td>@course.Title</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td>@course.Schedule</td>
                    <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}
else
{
    <p class="text-muted">No courses found matching your criteria.</p>
}

@code {
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Department> departments = new();
    private List<Course> courses = new();
    private string _searchTerm = string.Empty;
    private int _selectedDepartmentId;

    private string searchTerm
    {
        get => _searchTerm;
        set { _searchTerm = value; FilterCourses(); }
    }

    private int selectedDepartmentId
    {
        get => _selectedDepartmentId;
        set { _selectedDepartmentId = value; FilterCourses(); }
    }

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        _selectedDepartmentId = DepartmentId ?? 0;
        FilterCourses();
    }

    private void FilterCourses()
    {
        int? deptFilter = _selectedDepartmentId > 0 ? _selectedDepartmentId : null;
        courses = CatalogService.GetCourses(_searchTerm, deptFilter);
    }
}

