@page "/courses/{Id:int}"
@inject CatalogService CatalogService

<PageTitle>@(course?.Title ?? "Course Not Found")</PageTitle>

@if (course is null)
{
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
    <a href="courses" class="btn btn-primary">Back to Catalog</a>
}
else
{
    var dept = CatalogService.GetDepartment(course.DepartmentId);

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active">@course.CourseCode</li>
        </ol>
    </nav>

    <h1>@course.CourseCode &mdash; @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h4>Description</h4>
            <p>@course.Description</p>

            <h4 class="mt-4">Schedule</h4>
            <p>@course.Schedule</p>

            <h4 class="mt-4">Instructor</h4>
            <p><strong>@course.InstructorName</strong></p>
            <p>@course.InstructorBio</p>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Course Info</h5>
                    <ul class="list-unstyled">
                        <li><strong>Department:</strong> @dept?.Name</li>
                        <li><strong>Credits:</strong> @course.Credits</li>
                        <li><strong>Course Code:</strong> @course.CourseCode</li>
                    </ul>
                    <a href="enroll?courseId=@course.Id" class="btn btn-success w-100">Enroll in This Course</a>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? course;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourse(Id);
    }
}

@page "/enroll"
@inject CatalogService CatalogService
@rendermode InteractiveServer

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit the form below to request enrollment in a course.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted!</h4>
        <p>Thank you, <strong>@model.StudentName</strong>. Your enrollment request for
            <strong>@(CatalogService.GetCourse(model.CourseId)?.Title)</strong> has been received.
            You will be notified of your enrollment status.</p>
        <a href="courses" class="btn btn-primary">Browse More Courses</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-6">
            <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="enrollment">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <InputText id="studentName" class="form-control" @bind-Value="model.StudentName" />
                    <ValidationMessage For="() => model.StudentName" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" class="form-control" @bind-Value="model.StudentId" />
                    <ValidationMessage For="() => model.StudentId" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect id="courseId" class="form-select" @bind-Value="model.CourseId">
                        <option value="0">-- Select a course --</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id">@course.CourseCode - @course.Title</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => model.CourseId" class="text-danger" />
                </div>

                <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private EnrollmentRequest model = new();
    private List<Course> courses = new();
    private bool submitted;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();
        if (CourseId.HasValue)
            model.CourseId = CourseId.Value;
    }

    private void HandleSubmit()
    {
        submitted = true;
    }
}

